const sd = $getWorkflowStaticData('global');
sd.begruesst = sd.begruesst || [];
const setup = $('⚙️ Setup').first().json;
const orders = ($json.orders || []).filter(o => !o.cancelled_at && o.email && o.customer);
const raus = [];

for (const o of orders) {
  // Nur ERSTKAEUFER (orders_count == 1 heisst: das war die erste Bestellung)
  if (parseInt(o.customer.orders_count || 0) > 1) continue;
  if (sd.begruesst.includes(o.id)) continue;
  sd.begruesst.push(o.id);

  const vorname = o.customer.first_name || '';
  const artikel = (o.line_items || []).map(li => li.title).slice(0, 3).join(', ');

  const prompt = 'Du schreibst im Namen des Gruenders vom Onlineshop "' + setup.SHOP_NAME + '" (Nische: ' + setup.SHOP_NISCHE + ').\n' +
    'Der Kunde hat GESTERN zum ERSTEN Mal bestellt. Schreibe die Willkommens-Mail auf Deutsch (Du-Form), maximal 140 Woerter:\n\n' +
    'Daten:\n- Vorname: ' + (vorname || 'unbekannt (neutral anreden)') + '\n- Bestellt: ' + artikel + '\n- Versandzeit: ' + setup.VERSANDZEIT + '\n- Instagram: ' + setup.INSTAGRAM_HANDLE + '\n- TikTok: ' + setup.TIKTOK_HANDLE + '\n\n' +
    'Aufbau:\n' +
    '1. Herzlicher Willkommens-Moment (er ist jetzt Teil der Community)\n' +
    '2. Was passiert jetzt: Paket kommt in ' + setup.VERSANDZEIT + '\n' +
    '3. Ein ehrlicher Profi-Tipp, wie er aus dem gekauften Produkt das Maximum rausholt (passend zum Artikel!)\n' +
    '4. Einladung, auf Instagram/TikTok zu folgen (mit den Handles)\n' +
    'KEIN Rabattcode, KEIN Upselling - er hat gerade erst gekauft, es geht nur um ein gutes Gefuehl. Klingt wie vom Gruender persoenlich. Schlichtes, mobiltaugliches HTML mit Inline-CSS.\n' +
    'Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"betreff": "...", "html": "..."}';

  raus.push({ json: { order_id: o.id, email: o.email, vorname, artikel, prompt } });
}

if (sd.begruesst.length > 2000) sd.begruesst = sd.begruesst.slice(-2000);
return raus;

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { betreff: 'Willkommen in der Familie! 🎉', html: text };
}
const orig = $('🧠 Erstkäufer finden').item.json;
const setup = $('⚙️ Setup').first().json;
const empfaenger = setup.TEST_MODE === 'ja' ? setup.OWNER_EMAIL : orig.email;
return { json: {
  empfaenger,
  betreff: (setup.TEST_MODE === 'ja' ? '[TEST] ' : '') + daten.betreff,
  email_html: daten.html
}};
